#!/usr/bin/env python3
"""FizzBuzz implementation that prints numbers 1-100 with Fizz/Buzz rules."""

for i in range(1, 101):
    if i % 15 == 0:
        print("FizzBuzz")
    elif i % 3 == 0:
        print("Fizz")
    elif i % 5 == 0:
        print("Buzz")
    else:
        print(i)
